"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[14420],{91941:e=>{e.exports=JSON.parse('{"tag":{"label":"sound","permalink":"/dst-api-webdocs/docs/tags/sound","allTagsPath":"/dst-api-webdocs/docs/tags","count":26,"items":[{"id":"game-scripts/prefabs/armor_wagpunk","title":"Armor Wagpunk","description":"A wearable armor item that grants increased speed and defense based on target tracking duration, with visual and audio feedback across multiple performance stages.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_wagpunk"},{"id":"game-scripts/prefabs/deck_of_cards","title":"Deck Of Cards","description":"Manages a deck of playing cards with visual stack states, shuffling via punching, and reveal mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deck_of_cards"},{"id":"game-scripts/prefabs/diseaseflies","title":"Diseaseflies","description":"Spawns a non-persistent visual effects entity (flies swarm) attached to a parent entity, playing a looping animation and sound.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/diseaseflies"},{"id":"game-scripts/prefabs/diviningrodbase","title":"Diviningrodbase","description":"Acts as a base component for the divining rod that manages its state (locked/unlocked/stuck), visual states, and sound effects in coordination with the Teleportato.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/diviningrodbase"},{"id":"game-scripts/prefabs/dragonfurnace","title":"Dragonfurnace","description":"Manages the furnace\'s cooking, incineration, and hammering mechanics, including state transitions, sound handling, and loot generation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dragonfurnace"},{"id":"game-scripts/prefabs/flies","title":"Flies","description":"A decorative prefab that emits ambient fly sounds and animations based on player proximity, typically used for atmospheric effects in environments like caves and swamps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flies"},{"id":"game-scripts/components/freezefx","title":"Freezefx","description":"Manages dynamic visual and audio effects for fire-based entities, including flickering light, radius scaling, intensity control, and sound effects across multiple flame levels.","permalink":"/dst-api-webdocs/docs/game-scripts/components/freezefx"},{"id":"game-scripts/prefabs/global","title":"Global","description":"Defines global assets required for the game\'s frontend, UI, animations, shaders, fonts, and sound packages\u2014serving as a shared dependency container for the entire game and modding system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/global"},{"id":"game-scripts/prefabs/hermithouse_ornament","title":"Hermithouse Ornament","description":"A decorative inventory item that can be placed on the Hermithouse and emits sound and animation effects when interacted with.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermithouse_ornament"},{"id":"game-scripts/prefabs/icebox_coffin_bat_fx","title":"Icebox Coffin Bat Fx","description":"Spawns a non-persistent local visual FX entity (bat) with randomized animation variation and sound when triggered in non-dedicated servers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/icebox_coffin_bat_fx"},{"id":"game-scripts/components/incinerator","title":"Incinerator","description":"Handles the destruction of items inside a container when triggered, including optional sound playback, event dispatching, and kill/murder event propagation for living items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/incinerator"},{"id":"game-scripts/prefabs/lava_pond","title":"Lava Pond","description":"A large environmental hazard that emits heat, ignites nearby flammable objects on contact, propagates fire, and triggers music events when engaged by the Dragonfly boss.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lava_pond"},{"id":"game-scripts/prefabs/livinglog","title":"Livinglog","description":"A consumable and repair item that emits a sound effect when taken as fuel or ignited.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livinglog"},{"id":"game-scripts/prefabs/marionette_fx","title":"Marionette Fx","description":"Creates client-side visual effects for the Marionette stage actor\'s appearance and disappearance animations with fading and sound playback.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marionette_fx"},{"id":"game-scripts/prefabs/petrify_announce","title":"Petrify Announce","description":"Spawns a non-persistent FX entity that plays a petrification sound at the position of a target proxy, adjusted for distance from the focal point.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petrify_announce"},{"id":"game-scripts/prefabs/pigtorch_flame","title":"Pigtorch Flame","description":"A visual and audio FX entity representing a pigtorch flame, using layered animation levels and integrated fire effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch_flame"},{"id":"game-scripts/prefabs/slingshotmodscontainer","title":"Slingshotmodscontainer","description":"Manages the UI container for the slingshot mod interface, handling sound playback and container lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotmodscontainer"},{"id":"game-scripts/prefabs/smoke_plant","title":"Smoke Plant","description":"Renders a non-persistent visual FX entity with lighting and sound, used to simulate a smoldering smoke plant effect in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/smoke_plant"},{"id":"game-scripts/prefabs/structure_collapse_fx","title":"Structure Collapse Fx","description":"Creates non-persistent visual and audio effects for structure collapse events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/structure_collapse_fx"},{"id":"game-scripts/prefabs/superjump_fx","title":"Superjump Fx","description":"Spawns a visual and sound effect at a specified location to simulate the landing of a superjump, and optionally spawns associated debris.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/superjump_fx"},{"id":"game-scripts/prefabs/thunder_far","title":"Thunder Far","description":"Spawns a non-persistent local FX entity that plays a distant thunder sound.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thunder_far"},{"id":"game-scripts/prefabs/thurible_smoke","title":"Thurible Smoke","description":"Creates and manages a non-persistent particle effect (smoke and hand animation) for a Thurible item when active, including ambient looping sound playback.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thurible_smoke"},{"id":"game-scripts/prefabs/townportaltalisman","title":"Townportaltalisman","description":"Manages the behavior and animation of the Town Portal Talisman item, which links two portals for teleportation and updates state based on inventory and connection status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/townportaltalisman"},{"id":"game-scripts/prefabs/vault_switch","title":"Vault Switch","description":"A decorative interactive switch component used in vault-related structures, supporting both standalone and base-mounted configurations with associated sound and animation logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_switch"},{"id":"game-scripts/prefabs/wagboss_robot_leg","title":"Wagboss Robot Leg","description":"Manages the landing and blocking behavior of a boss-related physics-based obstacle that reacts to environmental changes and boss presence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagboss_robot_leg"},{"id":"game-scripts/prefabs/wagpunk_cagewall","title":"Wagpunk Cagewall","description":"A networked, animated wall entity that can be extended or retracted in response to game events, commonly used in the Wagpunk-themed environmental mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagpunk_cagewall"}],"unlisted":false}}')}}]);